function getHighlighter(): Promise<HighlighterGeneric<never, never>> {
  highlighterPromise ??= createHighlighter({
    'engine': createJavaScriptRegexEngine(),
    'langs':  [...SUPPORTED_LANGS],
    'themes': []
  });
  return highlighterPromise;
}

